import path from 'path';

const BASE_DIR = path.resolve('./safe-directory');

export default function handler(req, res) {
  const userInput = req.query.file;
  const resolvedPath = path.resolve(BASE_DIR, userInput);

  // Ensure resolved path is within the allowed base directory
  if (!resolvedPath.startsWith(BASE_DIR)) {
    return res.status(400).json({ error: 'Invalid path' });
  }

  // Proceed with safe path
}

// If using a Node.js XML parser like 'libxmljs' or similar:
// Switch to a safe JSON-only API:
export default function handler(req, res) {
  if (req.headers['content-type'] !== 'application/json') {
    return res.status(415).json({ error: 'Only application/json is accepted' });
  }
  // process JSON safely...
}

