// middleware.ts
import { withAuth } from 'next-auth/middleware';
import { NextResponse } from 'next/server';

export default withAuth(
  function middleware(req) {
    const token = req.nextauth.token;
    const isAdminRoute = req.nextUrl.pathname.startsWith('/admin');

    if (isAdminRoute && token?.role !== 'ADMIN') {
      return NextResponse.redirect(new URL('/auth/login', req.url));
    }
  },
  { callbacks: { authorized: ({ token }) => !!token } }
);

export const config = {
  matcher: ['/admin/:path*', '/manage/:path*', '/manager/:path*', '/management/:path*']
};

// Instead of: fetch('/api/web_experiments/?token=' + token)
// Use a POST request or Authorization header:
fetch('/api/web_experiments/', {
  method: 'GET',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json'
  }
});

// Server-side: read from header, not query param
export default function handler(req, res) {
  const token = req.headers['authorization']?.replace('Bearer ', '');
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  // validate token...
}

// Using @upstash/ratelimit with Redis:
import { Ratelimit } from '@upstash/ratelimit';
import { Redis } from '@upstash/redis';

const ratelimit = new Ratelimit({
  redis: Redis.fromEnv(),
  limiter: Ratelimit.slidingWindow(10, '1 m'), // 10 requests per minute
  analytics: true,
});

export default async function handler(req, res) {
  const identifier = req.headers['x-forwarded-for'] || req.socket.remoteAddress;
  const { success, limit, remaining, reset } = await ratelimit.limit(identifier);

  res.setHeader('X-RateLimit-Limit', limit);
  res.setHeader('X-RateLimit-Remaining', remaining);

  if (!success) {
    return res.status(429).json({ error: 'Too many requests' });
  }
  // proceed with auth logic
}

// NextAuth.js handles this automatically when configured correctly.
// Ensure your [...nextauth].ts config does not disable CSRF:
import NextAuth from 'next-auth';
import GoogleProvider from 'next-auth/providers/google';

export default NextAuth({
  providers: [
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET,
      // Do NOT set checks: [] as that disables state/PKCE
    })
  ],
  // NextAuth generates and validates state automatically
  // Do not override or disable the built-in CSRF protection
});

// In your NextAuth.js configuration:
export default NextAuth({
  cookies: {
    callbackUrl: {
      name: '__Secure-next-auth.callback-url',
      options: {
        httpOnly: true,      // Add this
        sameSite: 'lax',
        path: '/',
        secure: true
      }
    }
  },
  callbacks: {
    async redirect({ url, baseUrl }) {
      // Validate callback URL to prevent open redirect
      if (url.startsWith(baseUrl)) return url;
      if (url.startsWith('/')) return `${baseUrl}${url}`;
      return baseUrl;
    }
  }
});
